import{bQ as s,aL as n,u as t,G as i}from"./chunks/framework.D06dwy5q.js";const d=JSON.parse('{"title":"23｜协作机制：handoff、agents-as-tools 与 A2A","description":"","frontmatter":{},"headers":[],"relativePath":"19.AIOps/04.工程化与协作设计/23-协作机制-handoff-agents-as-tools与A2A.md","filePath":"19.AIOps/04.工程化与协作设计/23-协作机制-handoff-agents-as-tools与A2A.md","lastUpdated":null}'),e={name:"19.AIOps/04.工程化与协作设计/23-协作机制-handoff-agents-as-tools与A2A.md"};function h(p,a,l,o,g,k){return n(),t("div",null,[...a[0]||(a[0]=[i(`<h1 id="_23-协作机制-handoff、agents-as-tools-与-a2a" tabindex="-1">23｜协作机制：handoff、agents-as-tools 与 A2A <a class="header-anchor" href="#_23-协作机制-handoff、agents-as-tools-与-a2a" aria-label="Permalink to &quot;23｜协作机制：handoff、agents-as-tools 与 A2A&quot;">​</a></h1><p>上一篇选定了编排模式。但编排模式只说&quot;谁负责什么&quot;，没说 agent 之间控制权怎么传递。</p><p>orchestrator-worker 里，编排者调 worker，是&quot;调一下拿结果&quot;还是&quot;把整个对话交出去&quot;？这两种机制差别很大，直接影响谁能看到用户、谁对最终回答负责。本篇讲两种控制传递机制，以及跨框架协作的 A2A 协议。</p><h2 id="两种控制传递" tabindex="-1">两种控制传递 <a class="header-anchor" href="#两种控制传递" aria-label="Permalink to &quot;两种控制传递&quot;">​</a></h2><p>业界（OpenAI Agents SDK 是典型）把 agent 间的控制传递分成两种：handoff 和 agents-as-tools。差别在&quot;谁拥有最终回答&quot;。</p><h3 id="handoff-控制权整个交出去" tabindex="-1">handoff：控制权整个交出去 <a class="header-anchor" href="#handoff-控制权整个交出去" aria-label="Permalink to &quot;handoff：控制权整个交出去&quot;">​</a></h3><p>handoff 是一个 agent 把整个对话的控制权交给另一个 agent。交出去之后，接收的 agent 直接面对用户，负责后续回答，原 agent 退出。</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># triage agent 把控制权 handoff 给日志分析 agent</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">triage_agent </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Agent(</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;分诊&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    instructions</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;判断告警类型，路由给对应专家。&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    handoffs</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[log_analysis_agent, metric_analysis_agent],</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>handoff 的特点是：接收方 agent 直接回应用户，能看到完整对话历史，自己决定后续怎么走。这适合&quot;分诊后整个交给专家&quot;的场景——分诊 agent 判断这是日志问题，把对话交给日志分析 agent，日志分析 agent 接手后直接和用户交互，分诊 agent 不再插手。</p><p>适合用 handoff 的场景：专家应该接管整个后续交互、需要专家直接面对用户、路由本身是工作流的一部分。</p><p>代价：handoff 后原 agent 失去控制，全局视角变弱。如果专家 agent 走偏了，原 agent 没法纠正。多个 handoff 链起来后，谁对最终结果负责会变模糊。</p><h3 id="agents-as-tools-编排者保留控制权" tabindex="-1">agents-as-tools：编排者保留控制权 <a class="header-anchor" href="#agents-as-tools-编排者保留控制权" aria-label="Permalink to &quot;agents-as-tools：编排者保留控制权&quot;">​</a></h3><p>agents-as-tools 是编排者把其他 agent 当工具调用。被调用的 agent 返回结果，但控制权始终在编排者手里，编排者拼最终回答。</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 编排者把日志分析 agent 当工具调用</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">orchestrator </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Agent(</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;编排&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    instructions</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;调用专家获取分析结果，自己汇总最终回答。&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    tools</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[log_analysis_agent.as_tool(), metric_analysis_agent.as_tool()],</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>被调用的 agent 不直接面对用户，只返回结果给编排者。编排者可以并行调多个、可以组合多个结果、可以加统一的安全护栏。</p><p>适合用 agents-as-tools 的场景：编排者要保持控制、要组合多个专家的输出、要在统一地方加护栏。运维排查多数场景适合这个——编排者（主 agent）调用日志分析、指标分析、Runbook 检索，自己汇总成带证据的报告。</p><h3 id="怎么选" tabindex="-1">怎么选 <a class="header-anchor" href="#怎么选" aria-label="Permalink to &quot;怎么选&quot;">​</a></h3><p>判断标准很简单：专家该不该直接面对用户？</p><p>该直接面对，用 handoff——专家接管整个后续。不该直接面对，用 agents-as-tools——编排者调专家拿结果，自己面对用户。</p><p>两者可以混用。分诊 agent handoff 给某个专家，专家接管后仍然可以把别的 agent 当工具调，处理自己的子任务。</p><h2 id="a2a-跨框架协作" tabindex="-1">A2A：跨框架协作 <a class="header-anchor" href="#a2a-跨框架协作" aria-label="Permalink to &quot;A2A：跨框架协作&quot;">​</a></h2><p>handoff 和 agents-as-tools 都是在同一个 agent 框架内协作。如果两个 agent 来自不同框架、不同供应商呢？</p><p>Google 在 2025 年 4 月推出的 A2A（Agent-to-Agent）协议解决这个。它是一个开放标准，让不同框架、不同供应商的 agent 能互相发现、通信、协作。现在由 Linux Foundation 托管，Google、Atlassian、Salesforce 等几十家公司支持。</p><h3 id="a2a-和-mcp-的分工" tabindex="-1">A2A 和 MCP 的分工 <a class="header-anchor" href="#a2a-和-mcp-的分工" aria-label="Permalink to &quot;A2A 和 MCP 的分工&quot;">​</a></h3><p>A2A 和 MCP 不是竞争，是互补，管的是不同层面。</p><p><strong>MCP 是 agent-to-tool</strong>：agent 怎么连接工具、API、外部资源。第 24 篇会讲。agent 用 MCP 调搜索引擎、数据库、第三方 API。</p><p><strong>A2A 是 agent-to-agent</strong>：agent 之间怎么协作、委派任务、管理共享工作流。agent A 用 A2A 把一个子任务交给 agent B，agent B 处理完返回结果。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>agent A ──A2A──→ agent B</span></span>
<span class="line"><span>   │                │</span></span>
<span class="line"><span>  MCP              MCP</span></span>
<span class="line"><span>   │                │</span></span>
<span class="line"><span> 工具/API         工具/API</span></span></code></pre></div><p>一个完整的 agentic 系统里，agent 之间用 A2A 协调，每个 agent 用 MCP 连自己的工具。A2A 管 agent 间，MCP 管 agent 接工具，两层不冲突。</p><h3 id="什么时候用-a2a" tabindex="-1">什么时候用 A2A <a class="header-anchor" href="#什么时候用-a2a" aria-label="Permalink to &quot;什么时候用 A2A&quot;">​</a></h3><p>A2A 的价值在跨框架互操作。如果所有 agent 都是你自己用同一个框架建的，A2A 用不上——框架内部的 handoff 或 agents-as-tools 更直接。</p><p>A2A 适合：agent 来自不同团队、不同框架、不同供应商，需要协作。比如 ops-assistant（自建）要和一个第三方监控平台的 agent 协作，两边框架不同，A2A 提供统一通信标准。A2A 还支持 agent 发现——agent 能发现其他 agent 及其能力，MCP 做不到这点。</p><p>运维场景里，A2A 目前还偏新。多数项目所有 agent 自建，用 handoff 或 agents-as-tools 就够。A2A 在需要接入外部 agent 生态时才显出价值。</p><h2 id="两个反模式" tabindex="-1">两个反模式 <a class="header-anchor" href="#两个反模式" aria-label="Permalink to &quot;两个反模式&quot;">​</a></h2><p>不管用哪种机制，有两个反模式要避免。</p><p><strong>delegation loop（委托循环）</strong>。agent A 把任务委派给 B，B 又委派回 A，A 又委派给 B，无限循环。CrewAI 现在默认关掉 delegation 就是防这个。设计协作时要明确每个 agent 的职责边界，不让任务在 agent 间来回弹。</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 防委托循环：记录委派链，检测环</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">def</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> handoff</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(from_agent, to_agent, task, chain):</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> to_agent </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">in</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> chain:</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        raise</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> DelegationLoop(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;检测到委托循环: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">{</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">chain </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [to_agent]</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">}</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> to_agent.run(task, chain </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [to_agent])</span></span></code></pre></div><p><strong>retry storm（重试风暴）</strong>。一个 agent 失败后重试，触发另一个 agent 失败，又触发重试，连锁反应。需要全局速率限制和重试上限，不能让每个 agent 各自无限重试。</p><p>handoff 和 agents-as-tools 这两种机制，在 OpenAI Agents SDK 里就是同名概念，CrewAI 的 delegation 是 handoff 的变体。框架给了现成实现，但 delegation loop、retry storm 这些反模式框架不一定防得住——CrewAI 后来默认关掉 delegation 就是防循环，说明框架也在补这些判断。理解了原理，用框架时才知道哪些坑要自己防（第 25 篇展开框架对应关系）。</p><h2 id="协作机制之后" tabindex="-1">协作机制之后 <a class="header-anchor" href="#协作机制之后" aria-label="Permalink to &quot;协作机制之后&quot;">​</a></h2><p>agent 间的协作机制讲完了：同框架内用 handoff 或 agents-as-tools，跨框架用 A2A。但还有一个外部集成问题：agent 要用的工具，如果不想每个 agent 都自己实现一遍，怎么共享？</p><p>下一篇讲 MCP。它解决跨客户端共享工具的标准协议——一个工具按 MCP 暴露后，任何 agent 都能发现和调用。</p>`,42)])])}const A=s(e,[["render",h]]);export{d as __pageData,A as default};
